    87→    else {
    88→        op = ap;
    89→    }
    90→
    91→    // Will get native-byte order contiguous copy.
    92→    PyArray_Descr *descr = NPY_DT_CALL_ensure_canonical(PyArray_DESCR(op));
    93→    if (descr == NULL) {
    94→        return NULL;
    95→    }
    96→    ap = (PyArrayObject *)PyArray_FromArray(op, descr, NPY_ARRAY_DEFAULT);
    97→
    98→    Py_DECREF(op);
    99→    if (ap == NULL) {
   100→        return NULL;
   101→    }
   102→
   103→    // Decides the shape of the output array.
   104→    if (!keepdims) {
   105→        out_ndim = PyArray_NDIM(ap) - 1;
   106→        out_shape = PyArray_DIMS(ap);
   107→    }
   108→    else {
   109→        out_shape = _shape_buf;
   110→        if (axis_copy == NPY_RAVEL_AXIS) {
   111→            for (int i = 0; i < out_ndim; i++) {
   112→                out_shape[i] = 1;
   113→            }
   114→        }
   115→        else {
   116→            /*
   117→             * While `ap` may be transposed, we can ignore this for `out` because the
   118→             * transpose only reorders the size 1 `axis` (not changing memory layout).
   119→             */
   120→            memcpy(out_shape, original_op_shape, out_ndim * sizeof(npy_intp));
   121→            out_shape[axis] = 1;
   122→        }
   123→    }
   124→
   125→    if (is_argmax) {
   126→        func_name = "argmax";
   127→        arg_func = PyDataType_GetArrFuncs(PyArray_DESCR(ap))->argmax;
   128→    }
   129→    else {
   130→        func_name = "argmin";
   131→        arg_func = PyDataType_GetArrFuncs(PyArray_DESCR(ap))->argmin;
   132→    }
   133→    if (arg_func == NULL) {
   134→        PyErr_SetString(PyExc_TypeError,
   135→                "data type not ordered");
   136→        goto fail;
   137→    }
   138→    elsize = PyArray_ITEMSIZE(ap);
   139→    m = PyArray_DIMS(ap)[PyArray_NDIM(ap)-1];
   140→    if (m == 0) {
   141→        PyErr_Format(PyExc_ValueError,
   142→                    "attempt to get %s of an empty sequence",
   143→                    func_name);
   144→        goto fail;
   145→    }
   146→
   147→    if (!out) {
   148→        rp = (PyArrayObject *)PyArray_NewFromDescr(
   149→                Py_TYPE(ap), PyArray_DescrFromType(NPY_INTP),
   150→                out_ndim, out_shape, NULL, NULL,
   151→                0, (PyObject *)ap);
   152→        if (rp == NULL) {
   153→            goto fail;
   154→        }
   155→    }
   156→    else {
   157→        if ((PyArray_NDIM(out) != out_ndim) ||
   158→                !PyArray_CompareLists(PyArray_DIMS(out), out_shape,
   159→                                        out_ndim)) {
