   143→static PyObject *
   144→_get_keywords(int rtype, PyArrayObject *out)
   145→{
   146→    PyObject *kwds = NULL;
   147→    if (rtype != NPY_NOTYPE || out != NULL) {
   148→        kwds = PyDict_New();
   149→        if (rtype != NPY_NOTYPE) {
   150→            PyArray_Descr *descr;
   151→            descr = PyArray_DescrFromType(rtype);
   152→            if (descr) {
   153→                PyDict_SetItemString(kwds, "dtype", (PyObject *)descr);
   154→                Py_DECREF(descr);
   155→            }
   156→        }
   157→        if (out != NULL) {
   158→            PyDict_SetItemString(kwds, "out", (PyObject *)out);
   159→        }
   160→    }
   161→    return kwds;
   162→}
